module top_module (
    input clk,
    input sreset,
    output [2:0] q );reg [2:0] q_reg;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (sreset)
            q_reg <= 3'b000;
        else
            q_reg <= q_reg + 1;
    end

    assign q = q_reg;

endmodule
